Office.onReady((info) => {
    if (info.host === Office.HostType.Excel) {
        loadTabs();
        
        Excel.run(async (context) => {
            context.workbook.worksheets.onActivated.add(loadTabs);
            await context.sync();
        });
    }
});

function toggleSettingsMenu() {
    const panel = document.getElementById("settings-panel");
    panel.style.display = (panel.style.display === "block") ? "none" : "block";
}

function resetTabOrder() {
    localStorage.removeItem("custom_tab_order");
    loadTabs();
}

let currentDraggingButton = null;
let isDraggingActive = false;
let globalStartY = 0;

async function loadTabs() {
    await Excel.run(async (context) => {
        const sheets = context.workbook.worksheets;
        sheets.load("items/name,items/visibility,items/position,items/tabColor");
        const activeSheet = sheets.getActiveWorksheet();
        activeSheet.load("name");
        
        await context.sync();

        const isCompact = document.getElementById("pref-compact").checked;
        const useBgFill = document.getElementById("pref-bg-color").checked;
        const showHidden = document.getElementById("pref-show-hidden").checked;
        const useBlackBorder = document.getElementById("pref-active-border").checked;
        const useRounded = document.getElementById("pref-rounded").checked;
        const textAlignment = document.getElementById("pref-align").value;

        const container = document.getElementById("tab-container");
        container.innerHTML = ""; 

        let sheetItems = [...sheets.items];
        const savedOrderJson = localStorage.getItem("custom_tab_order");
        
        if (savedOrderJson) {
            const savedOrder = JSON.parse(savedOrderJson);
            sheetItems.sort((a, b) => {
                let indexA = savedOrder.indexOf(a.name);
                let indexB = savedOrder.indexOf(b.name);
                if (indexA === -1) indexA = 999;
                if (indexB === -1) indexB = 999;
                return indexA - indexB;
            });
        }

        sheetItems.forEach((sheet) => {
            const isSheetHidden = sheet.visibility !== "Visible";
            if (isSheetHidden && !showHidden) return;

            const btn = document.createElement("button");
            btn.className = "tab-button";
            btn.innerText = sheet.name;
            btn.setAttribute("data-sheet-name", sheet.name);
            
            btn.style.textAlign = textAlignment;

            if (isCompact) {
                btn.style.padding = "4px 8px";
                btn.style.marginBottom = "3px";
                btn.style.fontSize = "12px";
            } else {
                btn.style.padding = "10px";
                btn.style.marginBottom = "6px";
                btn.style.fontSize = "14px";
            }

            btn.style.borderRadius = useRounded ? (isCompact ? "4px" : "6px") : "0px";

            if (sheet.tabColor) {
                if (useBgFill) {
                    btn.style.backgroundColor = sheet.tabColor;
                    btn.style.borderLeftColor = "transparent";
                    if (isColorDark(sheet.tabColor)) btn.style.color = "#ffffff";
                } else {
                    btn.style.backgroundColor = "#ffffff";
                    btn.style.color = "#333333";
                    btn.style.borderLeftColor = sheet.tabColor;
                }
            } else {
                btn.style.backgroundColor = "#ffffff";
                btn.style.color = "#333333";
                btn.style.borderLeftColor = "transparent";
            }

            if (isSheetHidden) {
                btn.classList.add("hidden-sheet");
                btn.style.borderLeftColor = "#a6e3a1"; 
            }

            if (sheet.name === activeSheet.name) {
                if (useBlackBorder) {
                    btn.style.border = "1px solid #000000";
                    if (!useBgFill && sheet.tabColor && !isSheetHidden) {
                        btn.style.borderLeft = `4px solid ${sheet.tabColor}`;
                    } else if (isSheetHidden) {
                        btn.style.borderLeft = "4px solid #a6e3a1";
                    }
                } else {
                    btn.style.backgroundColor = useBgFill && sheet.tabColor ? sheet.tabColor : "#e1dfdd";
                }
                btn.style.fontWeight = "bold";
            }

            btn.addEventListener("mousedown", (e) => {
                currentDraggingButton = btn;
                isDraggingActive = false;
                globalStartY = e.clientY;
                btn.style.opacity = "0.6"; 
            });

            btn.onclick = async () => {
                if (btn.classList.contains("was-dragged-item")) {
                    btn.classList.remove("was-dragged-item");
                    return;
                }
                
                await Excel.run(async (ctx) => {
                    const targetSheet = ctx.workbook.worksheets.getItem(sheet.name);
                    if (sheet.visibility !== "Visible") targetSheet.visibility = "Visible";
                    targetSheet.activate();
                    await ctx.sync();
                });
            };

            container.appendChild(btn);
        });
    });
}

window.addEventListener("mousemove", (e) => {
    if (!currentDraggingButton) return;

    if (!isDraggingActive && Math.abs(e.clientY - globalStartY) > 3) {
        isDraggingActive = true;
        currentDraggingButton.classList.add("dragging");
    }

    if (isDraggingActive) {
        const container = document.getElementById("tab-container");
        const afterElement = getDragAfterElement(container, e.clientY);
        
        if (afterElement == null) {
            container.appendChild(currentDraggingButton);
        } else {
            container.insertBefore(currentDraggingButton, afterElement);
        }
    }
});

window.addEventListener("mouseup", () => {
    if (!currentDraggingButton) return;

    currentDraggingButton.style.opacity = "";
    currentDraggingButton.classList.remove("dragging");

    if (isDraggingActive) {
        currentDraggingButton.classList.add("was-dragged-item");
        saveCurrentOrderState();
    }

    currentDraggingButton = null;
    isDraggingActive = false;
});

function getDragAfterElement(container, y) {
    const draggableElements = [...container.querySelectorAll(".tab-button:not(.dragging)")];
    return draggableElements.reduce((closest, child) => {
        const box = child.getBoundingClientRect();
        const offset = y - box.top - box.height / 2;
        if (offset < 0 && offset > closest.offset) {
            return { offset: offset, element: child };
        } else {
            return closest;
        }
    }, { offset: Number.NEGATIVE_INFINITY }).element;
}

function saveCurrentOrderState() {
    const buttons = [...document.querySelectorAll("#tab-container .tab-button")];
    const orderArray = buttons.map(btn => btn.getAttribute("data-sheet-name"));
    localStorage.setItem("custom_tab_order", JSON.stringify(orderArray));
}

function isColorDark(hex) {
    if (!hex) return false;
    const cleanHex = hex.replace("#", "");
    const r = parseInt(cleanHex.substring(0, 2), 16);
    const g = parseInt(cleanHex.substring(2, 4), 16);
    const b = parseInt(cleanHex.substring(4, 6), 16);
    return ((0.2126 * r) + (0.7152 * g) + (0.0722 * b)) < 128;
}